import{_ as a,o as t,c as o,ai as r}from"./chunks/framework.CsYGeNYI.js";const p=JSON.parse('{"title":"Gateway Lock","description":"","frontmatter":{"summary":"Gateway singleton guard using the WebSocket listener bind","read_when":["Running or debugging the gateway process","Investigating single-instance enforcement"],"title":"Gateway Lock"},"headers":[],"relativePath":"gateway/gateway-lock.md","filePath":"gateway/gateway-lock.md","lastUpdated":null}'),s={name:"gateway/gateway-lock.md"};function i(n,e,l,c,h,d){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="gateway-lock" tabindex="-1"><a class="header-anchor" href="#gateway-lock">#</a> Gateway lock</h1><p>Last updated: 2025-12-11</p><h2 id="why" tabindex="-1"><a class="header-anchor" href="#why">#</a> Why</h2><ul><li>Ensure only one gateway instance runs per base port on the same host; additional gateways must use isolated profiles and unique ports.</li><li>Survive crashes/SIGKILL without leaving stale lock files.</li><li>Fail fast with a clear error when the control port is already occupied.</li></ul><h2 id="mechanism" tabindex="-1"><a class="header-anchor" href="#mechanism">#</a> Mechanism</h2><ul><li>The gateway binds the WebSocket listener (default <code>ws://127.0.0.1:18789</code>) immediately on startup using an exclusive TCP listener.</li><li>If the bind fails with <code>EADDRINUSE</code>, startup throws <code>GatewayLockError(&quot;another gateway instance is already listening on ws://127.0.0.1:&lt;port&gt;&quot;)</code>.</li><li>The OS releases the listener automatically on any process exit, including crashes and SIGKILL—no separate lock file or cleanup step is needed.</li><li>On shutdown the gateway closes the WebSocket server and underlying HTTP server to free the port promptly.</li></ul><h2 id="error-surface" tabindex="-1"><a class="header-anchor" href="#error-surface">#</a> Error surface</h2><ul><li>If another process holds the port, startup throws <code>GatewayLockError(&quot;another gateway instance is already listening on ws://127.0.0.1:&lt;port&gt;&quot;)</code>.</li><li>Other bind failures surface as <code>GatewayLockError(&quot;failed to bind gateway socket on ws://127.0.0.1:&lt;port&gt;: …&quot;)</code>.</li></ul><h2 id="operational-notes" tabindex="-1"><a class="header-anchor" href="#operational-notes">#</a> Operational notes</h2><ul><li>If the port is occupied by <em>another</em> process, the error is the same; free the port or choose another with <code>opensoul gateway --port &lt;port&gt;</code>.</li><li>The macOS app still maintains its own lightweight PID guard before spawning the gateway; the runtime lock is enforced by the WebSocket bind.</li></ul>',10)])])}const g=a(s,[["render",i]]);export{p as __pageData,g as default};
